const items = $input.all();

// если нет заявок (или пустая выдача)
if (!items.length) return [{ json: { ticket_id: "", is_active: false } }];

// сортировка по updatedAt (ISO строка ок)
items.sort((a, b) => {
  const da = new Date(a.json.updatedAt || a.json.updated_at || 0).getTime();
  const db = new Date(b.json.updatedAt || b.json.updated_at || 0).getTime();
  return db - da;
});

// вернуть только последнюю обновлённую
return [items[0]];

