const input = $input.first()?.json ?? {};

const alphabet = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
// Без I, O, 0, 1 — чтобы не путать символы.

let suffix = '';

for (let i = 0; i < 6; i++) {
  suffix += alphabet[Math.floor(Math.random() * alphabet.length)];
}

const ticket = `R${suffix}`;

return [
  {
    json: {
      ...input,
      ticket_id: ticket,
    },
  },
];

