const item = $input.first();
const json = item.json;

const operatorMessage = json.operator_message || '';
const replyText = json.reply_to_message_text || '';

// Сначала пытаемся найти ticket_id в сообщении, на которое оператор ответил.
// Если не нашли — ищем в тексте самого оператора.
const combinedSources = [
  replyText,
  operatorMessage,
];

let detectedTicketId = '';

for (const source of combinedSources) {
  const match = source.match(/#?(R\d{6,})/i);
  if (match) {
    detectedTicketId = match[1].toUpperCase();
    break;
  }
}

return [
  {
    json: {
      ...json,
      detected_ticket_id: detectedTicketId,
      ticket_id_source: replyText ? 'reply_or_text' : 'text_only',
    }
  }
];

